23.query:
fetch dt.entity.host
| fieldsAdd hostGroupName = if(isNull(hostGroupName),  "No group assigned", else: hostGroupName)
| fieldsAdd monitoringMode = if(isNotNull(monitoringMode), monitoringMode, 
else: if(isMonitoringCandidate, "MONITORING_CANDIDATE", 
else: if(standalone, "App only", else: "Unknown")))
| fieldsRemove entity.name
| fieldsRemove id
| summarize count(), by:{monitoringMode}    
| sort `count()` desc

28.query:
timeseries 
{
`NIC bytes received`=sum(dt.host.net.nic.bytes_rx, rollup: avg),
`NIC bytes sent`=sum(dt.host.net.nic.bytes_tx, rollup: avg)
}, by:{ dt.entity.host_group }
| fieldsAdd hostGroupName = if(isNull(entityName(dt.entity.host_group)),  "No group assigned", else:  entityName(dt.entity.host_group))

